import os
from langchain_core.callbacks import BaseCallbackHandler

os.environ["LANGCHAIN_TRACING_V2"] = "true"
os.environ["LANGCHAIN_PROJECT"] = "react-agent-prod"

# Custom callback to log each step to your own system
class StepLogger(BaseCallbackHandler):
    def __init__(self):
        self.steps: list[dict] = []

    def on_agent_action(self, action, **kwargs):
        self.steps.append({
            "type": "action",
            "tool": action.tool,
            "input": action.tool_input,
        })

    def on_tool_end(self, output: str, **kwargs):
        if self.steps:
            self.steps[-1]["observation"] = output[:500]  # truncate long results

    def on_agent_finish(self, finish, **kwargs):
        self.steps.append({
            "type": "final_answer",
            "output": finish.return_values.get("output", ""),
        })

logger = StepLogger()
result = executor.invoke(
    {"input": "What is 15% of the population of Tokyo?"},
    config={"callbacks": [logger]},
)

# Inspect the full trace
for step in logger.steps:
    print(step)

import traceback

def safe_tool_call(tool_fn, tool_input: str, timeout: float = 10.0) -> str:
    """Execute tool_fn(tool_input) with timeout and error normalization."""
    import concurrent.futures
    with concurrent.futures.ThreadPoolExecutor(max_workers=1) as ex:
        future = ex.submit(tool_fn, tool_input)
        try:
            return future.result(timeout=timeout)
        except concurrent.futures.TimeoutError:
            return f"Error: tool timed out after {timeout}s. Try a more specific query."
        except ValueError as e:
            return f"Error: invalid input — {e}. Check the tool's expected format."
        except Exception as e:
            return f"Error: {type(e).__name__}: {str(e)[:200]}. Try a different approach."

# Use in the main loop
def react_loop_with_recovery(question: str, tools: dict, max_steps: int = 8) -> str:
    llm = ChatOpenAI(model="gpt-4o-mini", temperature=0, stop=["Observation:"])
    scratchpad = f"Question: {question}\n"

    for _ in range(max_steps):
        response = llm.invoke(REACT_SYSTEM + "\n\n" + scratchpad)
        output = response.content
        scratchpad += output

        final = parse_final_answer(output)
        if final:
            return final

        action = parse_action(output)
        if action:
            tool_name, tool_input = action
            if tool_name in tools:
                observation = safe_tool_call(tools[tool_name], tool_input)
            else:
                observation = f"Error: tool '{tool_name}' not available. Use one of: {list(tools)}"
            scratchpad += f"\nObservation: {observation}\n"

    return "Reached step limit without a definitive answer."
